class SecureSearchQueryBuilder:
    """
    Builds parameterized PostgreSQL queries from validated, whitelisted inputs.

    Key security features:
    1. All table/column names are validated against a whitelist BEFORE use
    2. psycopg2.sql.Identifier is used for all dynamic identifiers
    3. All values use parameterized queries (psycopg2 %s placeholders)
    4. Query complexity is bounded (max filters, max depth)
    5. Pagination is enforced
    """

    MAX_FILTERS = 20
    MAX_SORT_FIELDS = 5

    def __init__(self, table_name: str):
        self.table_name = validate_table_name(table_name)
        self.schema = ALLOWED_SEARCH_SCHEMA[self.table_name]
        self.conditions = []
        self.params = []
        self.sort_clauses = []
        self.offset = 0
        self.limit = min(25, self.schema["max_results"])
        self._filter_count = 0

    def add_filter(self, column: str, operator: str, value=None):
        """Add a filter condition with full validation."""
        self._filter_count += 1
        if self._filter_count > self.MAX_FILTERS:
            raise QueryComplexityError(
                f"Too many filters. Maximum {self.MAX_FILTERS} allowed."
            )

        col = validate_column_name(self.table_name, column)
        op = validate_operator(operator)
        sql_op = ALLOWED_OPERATORS[op]

        col_identifier = psycopg2_sql.Identifier(col)

        if op in ("is_null", "is_not_null"):
            condition = psycopg2_sql.SQL("{} {}").format(
                col_identifier,
                psycopg2_sql.SQL(sql_op),
            )
            self.conditions.append(condition)

        elif op in ("in", "not_in"):
            if not isinstance(value, (list, tuple)) or len(value) == 0:
                raise InputValidationError(
                    f"Operator '{op}' requires a non-empty list value."
                )
            if len(value) > 100:
                raise InputValidationError(
                    f"IN clause limited to 100 values, got {len(value)}."
                )
            placeholders = psycopg2_sql.SQL(", ").join(
                [psycopg2_sql.Placeholder()] * len(value)
            )
            condition = psycopg2_sql.SQL("{} {} ({})").format(
                col_identifier,
                psycopg2_sql.SQL(sql_op),
                placeholders,
            )
            self.conditions.append(condition)
            self.params.extend(value)

        elif op in ("like", "not_like"):
            if not isinstance(value, str):
                raise InputValidationError("LIKE operator requires a string value.")
            value = sanitize_search_text(value, max_length=200)
            # Escape special LIKE characters in the value itself
            escaped_value = (
                value.replace("\\", "\\\\")
                .replace("%", "\\%")
                .replace("_", "\\_")
            )
            # Wrap with wildcards for contains-style search
            like_value = f"%{escaped_value}%"
            condition = psycopg2_sql.SQL("{} {}").format(
                col_identifier,
                psycopg2_sql.SQL(f"{sql_op} %s"),
            )
            self.conditions.append(condition)
            self.params.append(like_value)

        else:
            # Standard comparison operators: eq, neq, gt, gte, lt, lte
            condition = psycopg2_sql.SQL("{} {} %s").format(
                col_identifier,
                psycopg2_sql.SQL(sql_op),
            )
            self.conditions.append(condition)
            self.params.append(value)

        return self

    def add_full_text_search(self, search_text: str):
        """
        Add PostgreSQL full-text search using to_tsvector/to_tsquery.
        This is much faster than ILIKE for large datasets.
        """
        search_text = sanitize_search_text(search_text)
        if not search_text:
            return self

        ft_columns = self.schema.get("full_text_columns", [])
        if not ft_columns:
            raise InputValidationError(
                f"Full-text search not configured for '{self.table_name}'."
            )

        config = self.schema.get("full_text_search_config", "english")

        # Build tsvector from concatenated columns
        # e.g., to_tsvector('english', coalesce("name",'') || ' ' || coalesce("description",''))
        coalesce_parts = []
        for col in ft_columns:
            # Each column is validated via the schema definition
            part = psycopg2_sql.SQL("coalesce({}, '')").format(
                psycopg2_sql.Identifier(col)
            )
            coalesce_parts.append(part)

        concatenated = psycopg2_sql.SQL(" || ' ' || ").join(coalesce_parts)

        # Convert user search text to tsquery safely using plainto_tsquery
        # plainto_tsquery is safe - it doesn't interpret special tsquery operators
        condition = psycopg2_sql.SQL(
            "to_tsvector({config}, {cols}) @@ plainto_tsquery({config}, %s)"
        ).format(
            config=psycopg2_sql.Literal(config),
            cols=concatenated,
        )

        self.conditions.append(condition)
        self.params.append(search_text)
        return self

    def add_fuzzy_text_search(self, column: str, search_text: str):
        """
        Add ILIKE search on a specific column.
        Useful for autocomplete-style searches on individual fields.
        """
