# ---------------------------------------------------------------------------
# Query depth / complexity limiter middleware
# ---------------------------------------------------------------------------

class QueryDepthLimiter:
    """Middleware to limit query depth and prevent abuse."""

    MAX_DEPTH = 7
    MAX_QUERY_LENGTH = 5000

    def resolve(self, next, root, info, **args):
        if root is None:
            # Top-level resolution - check query complexity
            query_str = info.context.get("query_string", "") if isinstance(info.context, dict) else ""
            if len(query_str) > self.MAX_QUERY_LENGTH:
                raise Exception(
                    f"Query too large. Maximum {self.MAX_QUERY_LENGTH} characters."
                )
        return next(root, info, **args)


# ---------------------------------------------------------------------------
# Helper to coerce filter values to appropriate Python types
# ---------------------------------------------------------------------------

def coerce_filter_value(table_name: str, column: str, value_str: str):
    """Convert string value to appropriate Python type based on column schema."""
    col_type = ALLOWED_SEARCH_SCHEMA[table_name]["columns"].get(column)
    if col_type is None:
        raise InputValidationError(f"Unknown column: {column}")

    if value_str is None:
        return None

    try:
        if col_type == "integer":
            return int(value_str)
        elif col_type == "numeric":
            return float(value_str)
        elif col_type == "boolean":
            return value_str.lower() in ("true", "1", "yes", "t")
        elif col_type == "timestamp":
            return datetime.fromisoformat(value_str)
        else:
            return str(value_str)
    except (ValueError, TypeError) as e:
        raise InputValidationError(
            f"Invalid value '{value_str}' for column '{column}' "
            f"(expected {col_type}): {e}"
        )


# ---------------------------------------------------------------------------
# Execute search helper
# ---------------------------------------------------------------------------

def execute_search(builder: SecureSearchQueryBuilder, table_name: str) -> dict:
    """Execute the search query and return formatted results."""
    query, params = builder.build()

    columns = list(ALLOWED_SEARCH_SCHEMA[table_name]["columns"].keys())

    with get_db_cursor() as cursor:
        # Log the query for debugging (parameterized, safe to log)
        logger.debug("Executing search query on table: %s", table_name)

        cursor.execute(query, params)
        rows = cursor.fetchall()

        items = []
        for row in rows:
            row_dict = {}
            for i, col_name in enumerate(columns):
                val = row[i]
                # Convert non-serializable types
                if isinstance(val, datetime):
                    val = val.isoformat()
                row_dict[col_name] = val
            items.append(row_dict)

    # Get total count (rebuild conditions without pagination params)
    # We need a fresh builder for count, or we can do it inline
    count_query_parts = [
        psycopg2_sql.SQL("SELECT COUNT(*) FROM {}").format(
            psycopg2_sql.Identifier(table_name)
        )
    ]
    # params without the last 2 (LIMIT, OFFSET)
    count_params = params[:-2]

    if builder.conditions:
        where_clause = psycopg2_sql.SQL(" AND ").join(builder.conditions)
        count_query_parts.append(
            psycopg2_sql.SQL("WHERE {}").format(where_clause)
        )

    count_query = psycopg2_sql.SQL(" ").join(count_query_parts)

    with get_db_cursor() as cursor:
        cursor.execute(count_query, count_params)
        total_count = cursor.fetchone()[0]

    return {
        "items": items,
        "total_count": total_count,
        "offset": builder.offset,
        "limit": builder.limit,
        "has_more": (builder.offset + builder.limit) < total_count,
    }


