class Query(graphene.ObjectType):

    # Generic search endpoint
    search = graphene.Field(
        SearchResponse,
        resource=graphene.String(required=True, description="Resource type: products, users, articles"),
        query=graphene.String(description="Full-text search query"),
        filters=graphene.List(SearchFilterInput, description="Filter conditions"),
        sort=graphene.List(SortInput, description="Sort order"),
        offset=graphene.Int(default_value=0),
        limit=graphene.Int(default_value=25),
    )

    # Typed search endpoints
    search_products = graphene.Field(
        ProductSearchResponse,
        query=graphene.String(description="Full-text search query"),
        filters=graphene.List(SearchFilterInput),
        sort=graphene.List(SortInput),
        offset=graphene.Int(default_value=0),
        limit=graphene.Int(default_value=25),
        category=graphene.String(description="Shortcut filter for category"),
        min_price=graphene.Float(description="Shortcut filter for minimum price"),
        max_price=graphene.Float(description="Shortcut filter for maximum price"),
    )

    search_users = graphene.Field(
        UserSearchResponse,
        query=graphene.String(),
        filters=graphene.List(SearchFilterInput),
        sort=graphene.List(SortInput),
        offset=graphene.Int(default_value=0),
        limit=graphene.Int(default_value=25),
    )

    search_articles = graphene.Field(
        ArticleSearchResponse,
        query=graphene.String(),
        filters=graphene.List(SearchFilterInput),
        sort=graphene.List(SortInput),
        offset=graphene.Int(default_value=0),
        limit=graphene.Int(default_value=25),
        author=graphene.String(description="Shortcut filter for author"),
    )

    def resolve_search(self, info, resource, query=None, filters=None, sort=None,
                       offset=0, limit=25):
        try:
            builder = SecureSearchQueryBuilder(resource)
            builder.set_pagination(offset, limit)

            if query:
                builder.add_full_text_search(query)

            if filters:
                for f in filters:
                    op = validate_operator(f.operator)
                    if op in ("is_null", "is_not_null"):
                        builder.add_filter(f.field, f.operator)
                    elif op in ("in", "not_in"):
                        values = f.values or []
                        col = validate_column_name(resource, f.field)
                        coerced = [coerce_filter_value(resource, col, v) for v in values]
                        builder.add_filter(f.field, f.operator, coerced)
                    else:
                        col = validate_column_name(resource, f.field)
                        coerced = coerce_filter_value(resource, col, f.value)
                        builder.add_filter(f.field, f.operator, coerced)

            if sort:
                for s in sort:
                    builder.add_sort(s.field, s.direction or "asc")

            result = execute_search(builder, resource)

            return SearchResponse(
                items=[SearchResultItem(data=item) for item in result["items"]],
                total_count=result["total_count"],
                offset=result["offset"],
                limit=result["limit"],
                has_more=result["has_more"],
            )

        except (InputValidationError, QueryComplexityError) as e:
            raise Exception(str(e))

